return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var gridW = 120;
    var gridH = 120;
    var startX = (W - gridW) / 2;
    var startY = H / 2 - 80;
    var boxSize = gridW / 10;

    // Stages
    // 0 - 2s: empty grid (0%)
    // 2s - 4.5s: 1 square (1%)
    // 4.5s - 7s: 25 squares (25%)
    // 7s - 9.5s: 50 squares (50%)
    // 9.5s - 12s: 100 squares (100%)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    var fillCount = 0;
    var fillColor = '#1F2937';
    var stepText = '0% Shaded';
    var formulaText = '0 / 100 = 0.0';

    if (stage === 1) {
      fillCount = 0;
      fillColor = '#1F2937';
      stepText = '0% Shaded';
      formulaText = '0/100 = 0.0';
    } else if (stage === 2) {
      fillCount = 1;
      fillColor = '#EF4444'; // Red
      stepText = '1% Shaded';
      formulaText = '1/100 = 0.01';
    } else if (stage === 3) {
      fillCount = 25;
      fillColor = '#3B82F6'; // Blue
      stepText = '25% Shaded';
      formulaText = '25/100 = 1/4 = 0.25';
    } else if (stage === 4) {
      fillCount = 50;
      fillColor = '#10B981'; // Green
      stepText = '50% Shaded';
      formulaText = '50/100 = 1/2 = 0.50';
    } else {
      fillCount = 100;
      fillColor = '#8B5CF6'; // Purple
      stepText = '100% Shaded';
      formulaText = '100/100 = 1 (Whole)';
    }

    // Draw squares
    for (var r = 0; r < 10; r++) {
      for (var c = 0; c < 10; c++) {
        var idx = r * 10 + c;
        var rx = startX + c * boxSize;
        var ry = startY + r * boxSize;

        ctx.beginPath();
        ctx.rect(rx, ry, boxSize, boxSize);
        if (idx < fillCount) {
          ctx.fillStyle = fillColor;
        } else {
          ctx.fillStyle = '#1F2937';
        }
        ctx.fill();
        ctx.strokeStyle = '#374151';
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    }

    // Label text
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = fillColor;
    ctx.font = 'bold 16px -apple-system, sans-serif';
    ctx.fillText(stepText, W / 2, H - 42);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillText(formulaText, W / 2, H - 22);
  }
};
